package LED_Flashing {
  // Assumptions: LED Vf ≈ 2.0 V; target LED current 15 mA; components obtainable from Mouser.
  model LEDCircuitModel {
    requirement REQ_FREQ "LED flicker frequency" {
      id = "REQ-1"
      text = "LED flickers at 10 Hz ±5% (9.5 to 10.5 Hz) when powered from a 5 V supply."
    }
    requirement REQ_SUPPLY "5V supply" {
      id = "REQ-2"
      text = "Operates from a 5 V DC supply."
    }
    requirement REQ_CURRENT "Current limiting" {
      id = "REQ-3"
      text = "Provide current limiting to maintain LED current ≈15 mA and ≤20 mA."
    }
    requirement REQ_MOUSER "Sourceable from Mouser" {
      id = "REQ-4"
      text = "Required discrete components (LED, series resistor, oscillator or MCU) must be sourceable from Mouser."
    }
    block LEDFlasher {
      property Vcc: Real[1] { default = 5.0 }
      property f_target: Real[1] { default = 10.0 }
      constraint freq_tol { body = "f_target >= 9.5 and f_target <= 10.5" }
      property LED_Vf: Real[1] { default = 2.0 }
      property LED_I: Real[1] { default = 0.015 }
      property R_series: Real[1] { derived = true; body = "(Vcc - LED_Vf) / LED_I" }
    }
  }
}
